def get_username():
    global email
    AllEmail = set() 
    while True:
        try:
            LsD = ''.join(random.choices(string.ascii_letters + string.digits, k=32))
            bol = json.dumps({
                "id": str(random.randrange(10000, 72212872775)),
                "render_surface": "PROFILE"
            })
            response = requests.post(
                "https://www.instagram.com/api/graphql",
                headers={
                    "X-FB-LSD": LsD,
                    "User-Agent": str(Agent.user())
                },
                data={
                    "lsd": LsD,
                    "variables": bol,
                    "doc_id": "25618261841150840"
                }
            )
            username = response.json()['data']['user']['username']
            email = f"{username}@gmail.com"
            if email not in AllEmail:
                AllEmail.add(email)
                LookUpV1(email)
                CheckV1(email)
        except:
            try:
                res = requests.get(
                    f"https://i.instagram.com/api/v1/users/{random.randrange(10000, 72212872775)}/info/",
                    headers={
                        "User-Agent": str(Agent.user()),
                        "Connection": "close",
                        "Accept-Encoding": "gzip, deflate",
                        "Proxy-Connection": "keep-alive",
                        "Content-Type": "application/x-www-form-urlencoded; charset=UTF-8",
                        "Accept-Language": "en;q=1, ru;q=0.9, ar;q=0.8"
                    }
                )
                username = res.json()["user"]["username"]
                email = f"{username}@gmail.com"
                if email not in AllEmail:
                    AllEmail.add(email)
                    LookUpV1(email)
                    CheckV1(email)
            except:
                pass

        
threads = []
for i in range(10):
    t = threading.Thread(target=get_username)
    threads.append(t)
    t.start()
for t in threads:
    t.join()      	 